import{_ as e,a,b as d}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as r,c as o,a2 as i}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Cloudflare R2 渠道添加说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/upload/cloudflare-r2.md","filePath":"cn/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),c={name:"cn/upload/cloudflare-r2.md"};function u(h,t,n,s,b,p){return r(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="cloudflare-r2-渠道添加说明" tabindex="-1">Cloudflare R2 渠道添加说明 <a class="header-anchor" href="#cloudflare-r2-渠道添加说明" aria-label="Permalink to &quot;Cloudflare R2 渠道添加说明&quot;">​</a></h1><h2 id="适合什么场景" tabindex="-1">适合什么场景 <a class="header-anchor" href="#适合什么场景" aria-label="Permalink to &quot;适合什么场景&quot;">​</a></h2><ul><li>你已经把图床部署在 Cloudflare 上，希望直接使用同一个 Cloudflare 账号里的 R2 桶保存文件。</li><li>你不想再填写一套 S3 Endpoint、Access Key、Secret Key。</li><li>你希望文件读写都走 Worker / Pages 的 R2 绑定，配置尽量简单。</li></ul><p>一句话：</p><p>R2 这条渠道不是在图床后台手动创建账号，而是在 Cloudflare 后台先把 R2 桶绑定到项目，绑定变量名必须是 <code>img_r2</code>。</p><h2 id="添加前要准备什么" tabindex="-1">添加前要准备什么 <a class="header-anchor" href="#添加前要准备什么" aria-label="Permalink to &quot;添加前要准备什么&quot;">​</a></h2><ul><li>一个 Cloudflare 账号。</li><li>一个已经创建好的 R2 Bucket。</li><li>当前图床项目的 Cloudflare 后台管理权限。</li></ul><h2 id="cloudflare-后台配置" tabindex="-1">Cloudflare 后台配置 <a class="header-anchor" href="#cloudflare-后台配置" aria-label="Permalink to &quot;Cloudflare 后台配置&quot;">​</a></h2><h3 id="_1-创建-r2-bucket" tabindex="-1">1. 创建 R2 Bucket <a class="header-anchor" href="#_1-创建-r2-bucket" aria-label="Permalink to &quot;1. 创建 R2 Bucket&quot;">​</a></h3><ol><li>登录 Cloudflare Dashboard。</li><li>进入 <code>R2 Object Storage</code>。</li><li>点击创建 Bucket。</li><li>Bucket 名称自己决定，例如 <code>imgbed</code>。</li></ol><p>这个 Bucket 就是后面实际保存文件的地方。</p><p><img src="'+e+'" alt="创建一个存储桶 img-r2" loading="lazy"></p><h3 id="_2-绑定到图床项目" tabindex="-1">2. 绑定到图床项目 <a class="header-anchor" href="#_2-绑定到图床项目" aria-label="Permalink to &quot;2. 绑定到图床项目&quot;">​</a></h3><p>根据你的部署类型选择位置：</p><table tabindex="0"><thead><tr><th>部署类型</th><th>绑定位置</th></tr></thead><tbody><tr><td>Pages</td><td>当前 Pages 项目 -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>当前 Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>新增绑定时重点只看这一项：</p><table tabindex="0"><thead><tr><th>字段</th><th>填写</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>选择刚创建的 Bucket</td></tr></tbody></table><p>变量名必须写成 <code>img_r2</code>，代码里上传、读取、删除 R2 文件都只认这个绑定名。</p><h3 id="_3-重新部署" tabindex="-1">3. 重新部署 <a class="header-anchor" href="#_3-重新部署" aria-label="Permalink to &quot;3. 重新部署&quot;">​</a></h3><p>绑定保存后，需要重新部署一次图床项目，让 Worker / Pages 运行时真正拿到 <code>img_r2</code>。</p><h2 id="图床后台会看到什么" tabindex="-1">图床后台会看到什么 <a class="header-anchor" href="#图床后台会看到什么" aria-label="Permalink to &quot;图床后台会看到什么&quot;">​</a></h2><p>R2 绑定成功后，进入：</p><ol><li>系统配置。</li><li>上传设置。</li><li>查看 <code>Cloudflare R2</code> 渠道。</li></ol><p>系统会自动生成一条固定渠道：</p><table tabindex="0"><thead><tr><th>字段</th><th>固定值</th></tr></thead><tbody><tr><td>渠道名称</td><td><code>Cloudflare R2</code></td></tr><tr><td>渠道类型</td><td><code>cfr2</code></td></tr><tr><td>保存方式</td><td><code>binding</code></td></tr><tr><td>配置来源</td><td>环境绑定</td></tr></tbody></table><p>这条渠道是固定绑定渠道，不需要点击“添加渠道”手动创建，也不能像普通渠道一样删除。</p><h2 id="后台可编辑字段" tabindex="-1">后台可编辑字段 <a class="header-anchor" href="#后台可编辑字段" aria-label="Permalink to &quot;后台可编辑字段&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>作用</th><th>是否必填</th></tr></thead><tbody><tr><td>启用渠道</td><td>控制 R2 是否参与上传选择</td><td>是</td></tr><tr><td>Account ID</td><td>只在开启容量限制并查询官方 R2 用量时使用</td><td>开启容量限制时建议填写</td></tr><tr><td>Bucket 名称</td><td>只在开启容量限制并查询官方 R2 用量时使用</td><td>开启容量限制时建议填写</td></tr><tr><td>容量限制</td><td>控制这个 R2 渠道是否按容量阈值参与上传选择</td><td>否</td></tr><tr><td>阈值</td><td>容量达到多少比例后不再继续写入</td><td>开启容量限制时填写</td></tr></tbody></table><p>Account ID 可以在 Cloudflare 控制台右侧账号信息里复制，开启容量限制时填到后台即可。</p><p><img src="'+a+'" alt="获取账户 ID" loading="lazy"></p><h2 id="添加步骤" tabindex="-1">添加步骤 <a class="header-anchor" href="#添加步骤" aria-label="Permalink to &quot;添加步骤&quot;">​</a></h2><ol><li>在 Cloudflare 创建 R2 Bucket。</li><li>打开图床项目的 Cloudflare 设置。</li><li>新增 R2 bucket binding。</li><li><code>Variable name</code> 填 <code>img_r2</code>。</li><li><code>R2 bucket</code> 选择刚创建的 Bucket。</li><li>保存绑定并重新部署图床。</li><li>回到图床后台 -&gt; 系统配置 -&gt; 上传设置。</li><li>确认 <code>Cloudflare R2</code> 渠道已经出现，并保持启用。</li></ol><p>如果要让 R2 按容量阈值参与上传选择，就打开容量限制，填写 Account ID、Bucket 名称、容量上限和阈值后保存。</p><p><img src="'+d+'" alt="配置容量限制" loading="lazy"></p><h2 id="添加完成后怎么检查" tabindex="-1">添加完成后怎么检查 <a class="header-anchor" href="#添加完成后怎么检查" aria-label="Permalink to &quot;添加完成后怎么检查&quot;">​</a></h2><ul><li>上传设置里是否出现 <code>Cloudflare R2</code> 固定渠道。</li><li>渠道卡片是否显示为启用。</li><li>上传一个小文件，返回链接能否正常打开。</li><li>如果打开文件时报 <code>R2 database binding is not configured</code>，说明项目运行时没有拿到 <code>img_r2</code> 绑定，需要回 Cloudflare 检查变量名和重新部署。</li></ul>',36)])])}const g=l(c,[["render",u]]);export{m as __pageData,g as default};
